// 4 5 sec total time,
// this is O(n ^ 2)
function productExceptSelf(nums: number[]): number[] {
    const results: number[] = []

    for (let i = 0; i < nums.length; i++) {
        let product = 1;

        for (let j = 0; j < nums.length; j++) {
            if (j === i) continue;
            product = product * nums[j]!
        }
        results.push(product)
    }
    return results
};

